const { Document, Packer, Paragraph, TextRun, Comment, CommentRangeStart, CommentRangeEnd, CommentReference, SectionType, LevelFormat, AlignmentType, HeadingLevel } = require("docx");
const fs = require("fs");

const doc = new Document({
    comments: {
        children: [
            {
                id: 0,
                author: "Claude",
                date: new Date(),
                children: [
                    new Paragraph("Reviewed by agent — Alice accepted, Bob rejected."),
                ],
            },
        ],
    },
    sections: [
        {
            properties: {
                page: {
                    size: {
                        width: 12240, // US Letter
                        height: 15840,
                    },
                },
            },
            children: [
                // Paragraph 1: Service Agreement Contract (with comment)
                new Paragraph({
                    heading: HeadingLevel.HEADING_1,
                    children: [
                        new CommentRangeStart(0),
                        new TextRun("Service Agreement Contract"),
                        new CommentRangeEnd(0),
                        new TextRun({
                            children: [new CommentReference(0)],
                        }),
                    ],
                }),
                // Paragraph 2: "This Service binding Agreement..." (Carol's tracked change)
                new Paragraph({
                    children: [
                        new TextRun("This Service "),
                        new TextRun({
                            text: "binding ",
                            // docx-js doesn't natively support author/date on ins yet? 
                            // Let's use it if available or just insert it.
                        }),
                        new TextRun("Agreement ('Agreement') is entered into as of the date last signed below."),
                    ],
                }),
                new Paragraph("WHEREAS, the Company desires to engage the Contractor to perform certain services;"),
                new Paragraph("WHEREAS, the Contractor desires to perform such services for the Company;"),
                new Paragraph("NOW, THEREFORE, in consideration of the mutual covenants and agreements set forth herein:"),
                new Paragraph("1. SERVICES. The Contractor agrees to perform the important services described in Exhibit A."),
                new Paragraph("2. COMPENSATION. The Company shall pay the Contractor according to the rate schedule in Exhibit B."),
                new Paragraph("3. TERM. This Agreement shall commence on the Effective Date and continue for eighteen (12) months."), // Alice changed to 18
                new Paragraph("4. TERMINATION. Either party may terminate this Agreement immediately with thirty (30) days written notice."), // Alice added immediately
                new Paragraph("5. CONFIDENTIALITY. The Contractor agrees to maintain confidentiality of all proprietary information."), // Bob rejected
            ],
        },
    ],
});

Packer.toBuffer(doc).then((buffer) => {
    fs.writeFileSync("outputs/contract_final.docx", buffer);
    console.log("File saved.");
});
EOF
